// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

/**
 * Pins the advisory seek forwarding of {@link TripleSourceIterationWrapper}: the wrapper sits between the query
 * engine's binding-set converters and the store's ordered statement iteration, so if it swallows the hint the
 * leapfrogging merge join silently degrades to plain iteration.
 */
public class TripleSourceIterationWrapperSeekTest {

	private static final class RecordingSeekIteration implements CloseableIteration<String> {

		private final Iterator<String> elements;
		private final List<Value> seekTargets = new ArrayList<>();

		private RecordingSeekIteration(List<String> elements) {
			this.elements = elements.iterator();
		}

		@Override
		public boolean hasNext() {
			return elements.hasNext();
		}

		@Override
		public String next() {
			return elements.next();
		}

		@Override
		public void seek(Value minValue, boolean minInclusive, Value maxValue, boolean maxInclusive) {
			seekTargets.add(minValue);
		}

		@Override
		public boolean supportsSeek() {
			return true;
		}

		@Override
		public void close() {
		}
	}

	@Test
	public void forwardsSeekToTheDelegate() {
		RecordingSeekIteration delegate = new RecordingSeekIteration(List.of("a", "b"));
		Value target = SimpleValueFactory.getInstance().createIRI("http://example.com/target");
		try (TripleSourceIterationWrapper<String> wrapper = new TripleSourceIterationWrapper<>(delegate)) {
			assertTrue(wrapper.supportsSeek());
			wrapper.seek(target, true, null, true);
			assertEquals(List.of(target), delegate.seekTargets);
		}
	}

	@Test
	public void closedWrapperDeclines() {
		RecordingSeekIteration delegate = new RecordingSeekIteration(List.of("a"));
		TripleSourceIterationWrapper<String> wrapper = new TripleSourceIterationWrapper<>(delegate);
		wrapper.close();
		assertFalse(wrapper.supportsSeek());
		wrapper.seek(SimpleValueFactory.getInstance().createIRI("http://example.com/target"), true, null, true);
		assertTrue(delegate.seekTargets.isEmpty());
	}

	@Test
	public void plainDelegateReportsNoSeekSupport() {
		CloseableIteration<String> plain = new CloseableIteration<>() {

			private final Iterator<String> elements = List.of("a").iterator();

			@Override
			public boolean hasNext() {
				return elements.hasNext();
			}

			@Override
			public String next() {
				return elements.next();
			}

			@Override
			public void close() {
			}
		};
		try (TripleSourceIterationWrapper<String> wrapper = new TripleSourceIterationWrapper<>(plain)) {
			assertFalse(wrapper.supportsSeek());
		}
	}
}
